FROM medicines
WHERE therapeutic_class_id = 101;

external_knowledge:
- 'top 5 medicines' refers to the medicines with the highest total demand;
- 'in the highest demand' means the medicines that have been requested the most frequently or in the largest quantities;
- 'over the past month' refers to the last 30 days.

